1	import { useState } from 'react';
2	import { CardList } from '@/shared/components/CardList/CardList';
3	import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
4	import { Input } from '@/shared/components/ui/input';
5	import { Label } from '@/shared/components/ui/label';
6	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
7	import { Badge } from '@/shared/components/ui/badge';
8	import { emptyToNull } from '@/shared/query/queryHelpers';
9	import { useListPage } from '@/shared/hooks/useListPage';
10	import { DomainDetailDialog } from './DomainDetailDialog';
11	
12	const dataTypeOptions = Object.freeze(['', 'VARCHAR', 'CHAR', 'NUMERIC', 'DATETIME']);
13	
14	const initialFilters = Object.freeze({
15	    stdDmnNm: '',
16	    stdDmnGroupNm: '',
17	    stdDmnClsfNm: '',
18	    dataTypeNm: '',
19	    useYn: '',
20	});
21	
22	const DomainCard = ({ domain, onClick }) => (
23	    <button
24	        type='button'
25	        onClick={() => onClick(domain)}
26	        className='w-full text-left bg-card border border-border rounded-[10px] p-3.5 px-4 cursor-pointer transition-all hover:border-primary hover:shadow-[0_2px_8px_rgba(37,99,235,0.08)]'
27	    >
28	        <div className='flex items-start justify-between gap-3'>
29	            <div className='min-w-0 flex-1'>
30	                <div className='mb-1'>
31	                    <span className='text-[15px] font-semibold text-foreground'>
32	                        {domain.stdDmnNm}
33	                    </span>
34	                </div>
35	                <div className='text-[13px] text-muted-foreground flex items-center gap-4 flex-wrap'>
36	                    {domain.stdDmnGroupNm && <span>{domain.stdDmnGroupNm}</span>}
37	                    {domain.stdDmnClsfNm && <span>{domain.stdDmnClsfNm}</span>}
38	                    {domain.dataLen && (
39	                        <span>
40	                            {domain.dataTypeNm}({domain.dataLen}
41	                            {domain.unitNm ? ` ${domain.unitNm}` : ''})
42	                        </span>
43	                    )}
44	                    {domain.enctCycl && <span>제정 {domain.enctCycl}차</span>}
45	                </div>
46	            </div>
47	            <div className='flex items-center gap-1.5 shrink-0'>
48	                {domain.dataTypeNm && !domain.dataLen && (
49	                    <Badge variant='info'>
50	                        {domain.dataTypeNm}
51	                    </Badge>
52	                )}
53	                <Badge variant={domain.useYn === 'Y' ? 'success' : 'muted'}>
54	                    {domain.useYn === 'Y' ? '사용' : '미사용'}
55	                </Badge>
56	            </div>
57	        </div>
58	    </button>
59	);
60	
61	export const DomainListPage = () => {
62	    const [filters, setFilters] = useState(initialFilters);
63	    const { request, setRequest, setSelectedId, isDetailOpen, pageQuery, detailQuery } = useListPage({
64	        listQueryKey: 'domain-list',
65	        listUrl: '/domains/search',
66	        detailQueryKey: 'domain-detail',
67	        detailUrl: '/domains',
68	        initialRequest: { page: 1, size: 20 },
69	    });
70	
71	    return (
72	        <div className='space-y-4'>
73	            <h1 className='text-lg font-bold text-foreground m-0'>
74	                도메인 목록
75	            </h1>
76	
77	            <SearchForm
78	                onSubmit={() => {
79	                    setRequest({
80	                        page: 1,
81	                        size: request.size,
82	                        stdDmnNm: emptyToNull(filters.stdDmnNm),
83	                        stdDmnGroupNm: emptyToNull(filters.stdDmnGroupNm),
84	                        stdDmnClsfNm: emptyToNull(filters.stdDmnClsfNm),
85	                        dataTypeNm: emptyToNull(filters.dataTypeNm),
86	                        useYn: emptyToNull(filters.useYn),
87	                    });
88	                }}
89	                onReset={() => {
90	                    setFilters(initialFilters);
91	                    setRequest({ page: 1, size: request.size });
92	                }}
93	            >
94	                <div className='grid w-full gap-3 md:grid-cols-2 xl:grid-cols-5'>
95	                    <div className='space-y-2'>
96	                        <Label htmlFor='stdDmnNm'>도메인명</Label>
97	                        <Input
98	                            id='stdDmnNm'
99	                            value={filters.stdDmnNm}
100	                            onChange={(event) =>
101	                                setFilters((current) => ({ ...current, stdDmnNm: event.target.value }))
102	                            }
103	                        />
104	                    </div>
105	                    <div className='space-y-2'>
106	                        <Label htmlFor='stdDmnGroupNm'>그룹명</Label>
107	                        <Input
108	                            id='stdDmnGroupNm'
109	                            value={filters.stdDmnGroupNm}
110	                            onChange={(event) =>
111	                                setFilters((current) => ({ ...current, stdDmnGroupNm: event.target.value }))
112	                            }
113	                        />
114	                    </div>
115	                    <div className='space-y-2'>
116	                        <Label htmlFor='stdDmnClsfNm'>분류명</Label>
117	                        <Input
118	                            id='stdDmnClsfNm'
119	                            value={filters.stdDmnClsfNm}
120	                            onChange={(event) =>
121	                                setFilters((current) => ({ ...current, stdDmnClsfNm: event.target.value }))
122	                            }
123	                        />
124	                    </div>
125	                    <div className='space-y-2'>
126	                        <Label htmlFor='dataTypeNm'>데이터타입</Label>
127	                        <Select
128	                            value={filters.dataTypeNm || 'ALL'}
129	                            onValueChange={(value) =>
130	                                setFilters((current) => ({ ...current, dataTypeNm: value === 'ALL' ? '' : value }))
131	                            }
132	                        >
133	                            <SelectTrigger id='dataTypeNm' className='bg-background'>
134	                                <SelectValue placeholder='전체' />
135	                            </SelectTrigger>
136	                            <SelectContent>
137	                                <SelectItem value='ALL'>전체</SelectItem>
138	                                {dataTypeOptions.filter(opt => opt !== '').map((option) => (
139	                                    <SelectItem key={option} value={option}>
140	                                        {option}
141	                                    </SelectItem>
142	                                ))}
143	                            </SelectContent>
144	                        </Select>
145	                    </div>
146	                    <div className='space-y-2'>
147	                        <Label htmlFor='useYn'>사용여부</Label>
148	                        <Select
149	                            value={filters.useYn || 'ALL'}
150	                            onValueChange={(value) =>
151	                                setFilters((current) => ({ ...current, useYn: value === 'ALL' ? '' : value }))
152	                            }
153	                        >
154	                            <SelectTrigger id='useYn' className='bg-background'>
155	                                <SelectValue placeholder='전체' />
156	                            </SelectTrigger>
157	                            <SelectContent>
158	                                <SelectItem value='ALL'>전체</SelectItem>
159	                                <SelectItem value='Y'>사용</SelectItem>
160	                                <SelectItem value='N'>미사용</SelectItem>
161	                            </SelectContent>
162	                        </Select>
163	                    </div>
164	                </div>
165	            </SearchForm>
166	
167	            <CardList
168	                pageData={pageQuery.data ?? null}
169	                pageSizeOptions={[10, 20, 50, 100]}
170	                onPageChange={({ page, size }) => setRequest((current) => ({ ...current, page, size }))}
171	                renderItem={(domain) => (
172	                    <DomainCard key={domain.id} domain={domain} onClick={(d) => setSelectedId(d.id)} />
173	                )}
174	            />
175	
176	            <DomainDetailDialog
177	                domain={detailQuery.data ?? null}
178	                open={isDetailOpen}
179	                onOpenChange={(open) => {
180	                    if (!open) setSelectedId(null);
181	                }}
182	            />
183	        </div>
184	    );
185	};
